Vue.config.devtools=!1,Vue.config.debug=!1,Vue.config.silent=!0,Vue.config.ignoredElements=["app"];var app=new Vue({el:"#app",data:{source:"https://blue-heart-48ff.bigtentgames.workers.dev/",isFetching:!1,rawStats:[],stats:[],error:"",userSettingsUsesLightTheme:!1},methods:{async LoadPage(){this.CheckTheme(),await this.GetStats(),this.stats=this.ProcessRawStats()},async GetStats(){this.isFetching=!0;try{let e=await fetch(this.source,{method:"GET",headers:{"Content-Type":"application/json"}});e.ok?(this.rawStats=await e.json(),this.isFetching=!1):(this.error="Error fetching data: "+e.statusText,this.isFetching=!1)}catch(e){this.error="Error fetching data: "+e,this.isFetching=!1}},CheckTheme(){let e=localStorage.getItem("userSettingsUsesLightTheme");null!=e&&(this.userSettingsUsesLightTheme=JSON.parse(e))},ProcessRawStats(){let e=[];e.push({key:"Basic",value:[{key:"Total Games Created",value:this.rawStats.totalGames},{key:"Crazy Hard Games",value:this.rawStats.totalHardGames}]});let t=[];this.rawStats.languagesCount.forEach((e=>{t.push({key:AllLanguages.find((t=>t.tag===e.lang)).name+" Games",value:e.count})})),t.sort(((e,t)=>t.value-e.value)),e.push({key:"Languages",value:t});let a=[];return this.rawStats.wordsetIDCount.forEach((e=>{a.push({key:WordSets.find((t=>t.id===e.id)).name+" Games",value:e.count})})),a.sort(((e,t)=>t.value-e.value)),e.push({key:"Categories",value:a}),e},HandleOnVisibilityChange(e){this.CheckTheme()}},mounted(){this.LoadPage(),window.addEventListener("visibilitychange",this.HandleOnVisibilityChange)},watch:{},computed:{getLanguageCounts:function(){return[]}}});